const entrada = $input.all()[0].json.body;

const admins = entrada.adminsNotificacao || [];

// função de normalização
function normalizarTelefone(numero) {
  if (!numero) return null;

  let telefone = numero.replace(/\D/g, '');

  // remove 0 inicial
  if (telefone.startsWith('0')) {
    telefone = telefone.slice(1);
  }

  // adiciona DDI Brasil se não existir
  if (!telefone.startsWith('55')) {
    telefone = '55' + telefone;
  }

  return telefone;
}

const resultado = admins
  .map(admin => {

    const canaisAtivos = Object.entries(admin.canais || {})
      .filter(([_, ativo]) => ativo === true)
      .map(([canal]) => canal);

    if (canaisAtivos.length === 0) return null;

    return {
      json: {
        id: admin.id,
        nome: admin.nome,
        email: admin.email,
        telefone: normalizarTelefone(admin.telefone),
        canaisAtivos
      }
    };
  })
  .filter(Boolean);

return resultado;

